17	const InvoicePage = async ({ searchParams }: InvoicePageProps) => {
18	    const params = await searchParams;
19	
20	    const now = new Date();
21	    // Default to next month since the invoice covers the coming month's bookings
22	    const nextMonth = new Date(now.getFullYear(), now.getMonth() + 1, 1);
23	
24	    const year = params.year ? parseInt(params.year, 10) : nextMonth.getFullYear();
25	    const month = params.month ? parseInt(params.month, 10) : nextMonth.getMonth() + 1;
26	
27	    const gameDaysRaw = await gameDayService.getForMonth(year, month);
28	
29	    // A game day is considered to have a game scheduled if either the 'game'
30	    // flag is true or if the invitations were sent (mailSent is not null).
31	    const gameDays = gameDaysRaw.map((gd) => ({
32	        id: gd.id,
33	        date: formatDate(gd.date),
34	        gameScheduled: gd.game || (gd.mailSent !== null),
35	        hallCost: gd.hallCost,
36	    }));
37	
38	    return (
39	        <Container size="lg" py="lg">
40	            <AutoRefresh channels={[FootyChannel.Games, FootyChannel.Money]} />
41	            <InvoiceForm
42	                year={year}
43	                month={month}
44	                gameDays={gameDays}
45	                onUpdateGameDays={updateInvoiceGameDays}
46	                onRecordHallHire={recordHallHire}
47	            />
48	        </Container>
49	    );
50	};
51	
52	export default InvoicePage;
