1	/**
2	 * Returns the normalized public base URL for the application.
3	 *
4	 * Checks SITE_URL first (server-only, read at runtime — not baked in at build
5	 * time), then NEXT_PUBLIC_SITE_URL (inlined at build time for both client and
6	 * server bundles), then BETTER_AUTH_URL, then the current browser origin, and
7	 * finally falls back to http://localhost:3000.
8	 */
9	export function getPublicBaseUrl(): string {
10	    const runtimeUrl = process.env.SITE_URL?.trim();
11	    if (runtimeUrl) {
12	        return runtimeUrl.replace(/\/+$/, '');
13	    }
14	
15	    const envUrl = process.env.NEXT_PUBLIC_SITE_URL?.trim();
16	    if (envUrl) {
17	        return envUrl.replace(/\/+$/, '');
18	    }
19	
20	    const serverUrl = process.env.BETTER_AUTH_URL?.trim();
21	    if (serverUrl) {
22	        return serverUrl.replace(/\/+$/, '');
23	    }
24	
25	    if (typeof window !== 'undefined' && window.location?.origin) {
26	        return window.location.origin;
27	    }
28	
29	    return 'http://localhost:3000';
30	}
