5	const log = debug('footy:dates');
6	
7	/** URL for the UK Government Bank Holidays API. */
8	const BANK_HOLIDAYS_API_URL = 'https://www.gov.uk/bank-holidays.json';
9	
10	/** Cache duration for bank holiday data (24 hours). */
11	const BANK_HOLIDAYS_CACHE_TTL_MS = 24 * 60 * 60 * 1000;
12	
13	/** Cached bank holiday date strings in YYYY-MM-DD format. */
14	let bankHolidaysCache: Set<string> | null = null;
15	
16	/** Timestamp when the cache was last populated. */
17	let bankHolidaysCacheTime = 0;
18	
19	/**
20	 * Shape of a single bank holiday event from the UK Government API.
21	 */
22	interface BankHolidayEvent {
23	    title: string;
24	    date: string;
25	    notes: string;
26	    bunting: boolean;
27	}
28	
29	/**
30	 * Response shape from the UK Government Bank Holidays API.
31	 */
32	interface BankHolidaysResponse {
33	    'england-and-wales': {
34	        division: string;
35	        events: BankHolidayEvent[];
36	    };
37	}
38	
39	/**
40	 * Formats a Date as a YYYY-MM-DD string for comparison with bank holiday API
41	 * dates.
42	 *
43	 * @param date - The date to format
44	 * @returns Date string in YYYY-MM-DD format
45	 */
46	const formatDateKey = (date: Date): string => {
47	    const year = date.getFullYear();
48	    const month = String(date.getMonth() + 1).padStart(2, '0');
49	    const day = String(date.getDate()).padStart(2, '0');
50	    return `${year}-${month}-${day}`;
51	};
52	
53	/**
54	 * Fetches England and Wales bank holiday dates from the UK Government API,
55	 * with a 24-hour in-memory cache to avoid repeated requests.
56	 *
57	 * @see https://www.api.gov.uk/gds/bank-holidays/#bank-holidays
58	 * @returns A Set of date strings in YYYY-MM-DD format representing bank
59	 * holidays. Falls back to cached data or an empty set on failure.
60	 */
61	export async function getBankHolidays(): Promise<Set<string>> {
62	    const now = Date.now();
63	    if (bankHolidaysCache && (now - bankHolidaysCacheTime) < BANK_HOLIDAYS_CACHE_TTL_MS) {
64	        return bankHolidaysCache;
65	    }
66	
67	    try {
68	        const response = await fetch(BANK_HOLIDAYS_API_URL);
69	        if (!response.ok) {
70	            log('Failed to fetch bank holidays: %s %s', response.status, response.statusText);
71	            return bankHolidaysCache ?? new Set();
72	        }
73	
74	        const data = await response.json() as BankHolidaysResponse;
75	        const dates = new Set(
76	            data['england-and-wales'].events.map((event) => event.date),
77	        );
78	        bankHolidaysCache = dates;
79	        bankHolidaysCacheTime = now;
80	        log('Fetched %d bank holidays', dates.size);
81	        return dates;
82	    } catch (error) {
83	        log('Error fetching bank holidays: %O', error);
84	        return bankHolidaysCache ?? new Set();
85	    }
86	}
87	
88	/**
89	 * Snapshot of the module-level bank holiday cache state.
90	 *
91	 * Exported for testing only so unit tests can verify whether a successful fetch
92	 * updated both the cached date set and its associated timestamp, without
93	 * mutating the internal cache by reference.
94	 */
95	interface BankHolidaysCacheState {
96	    /**
97	     * Cached bank holiday date keys, or `null` when no cache has been populated.
98	     */
99	    cache: Set<string> | null;
100	    /**
101	     * Epoch milliseconds representing when the cache was last refreshed.
102	     */
103	    cacheTime: number;
104	}
105	
106	/**
107	 * Returns a defensive snapshot of the current bank holiday cache state.
108	 *
109	 * Exported for testing only so the `getBankHolidays` test suite can assert
110	 * cache and timestamp updates without depending on untyped module internals.
111	 *
112	 * @returns A snapshot containing a cloned cached set, if present, and the
113	 * current cache timestamp.
114	 */
115	export function getBankHolidaysCacheState(): BankHolidaysCacheState {
116	    return {
117	        cache: bankHolidaysCache ? new Set(bankHolidaysCache) : null,
118	        cacheTime: bankHolidaysCacheTime,
119	    };
120	}
121	
122	/**
123	 * Primes the module-level bank holiday cache with known values.
124	 *
125	 * Exported for testing only so unit tests can deterministically exercise cache
126	 * hit and failed-fetch fallback behaviour without making a real network
127	 * request.
128	 *
129	 * @param dates - Date keys to store in the cache.
130	 * @param cacheTime - Epoch milliseconds to associate with the primed cache.
131	 */
132	export function primeBankHolidaysCacheForTesting(
133	    dates: Iterable<string>,
134	    cacheTime: number = Date.now(),
135	): void {
136	    bankHolidaysCache = new Set(dates);
137	    bankHolidaysCacheTime = cacheTime;
138	}
139	
140	/**
141	 * Resets the bank holidays cache. Exported for testing only.
142	 */
143	export function resetBankHolidaysCache(): void {
144	    bankHolidaysCache = null;
145	    bankHolidaysCacheTime = 0;
146	}
147	
148	/**
149	 * Determines if a given date falls on a working day (not a weekend and not a
150	 * UK bank holiday).
151	 *
152	 * @param date - The date to check
153	 * @param bankHolidays - Set of bank holiday dates in YYYY-MM-DD format
154	 * @returns `true` if the date is a working day, `false` if it's a weekend or
155	 * bank holiday
156	 *
157	 * @example
158	 * ```ts
159	 * const bankHols = new Set(['2024-01-01']);
160	 * isWorkingDay(new Date('2024-01-15'), bankHols); // true (Monday)
161	 * isWorkingDay(new Date('2024-01-13'), bankHols); // false (Saturday)
162	 * isWorkingDay(new Date('2024-01-01'), bankHols); // false (bank holiday)
163	 * ```
164	 */
165	export const isWorkingDay = (date: Date, bankHolidays: Set<string>) => {
166	    const day = date.getDay();
167	    if (day === 0 || day === 6) return false;
168	    return !bankHolidays.has(formatDateKey(date));
169	};
