3	import { ClientSecretCredential } from '@azure/identity';
4	import { BlobServiceClient, ContainerClient } from '@azure/storage-blob';
5	
6	import { STORAGE_ACCOUNT_NAME } from '@/lib/azureConfig';
7	import { InternalError, normalizeUnknownError } from '@/lib/errors';
8	import { getSecrets } from '@/lib/secrets';
9	
10	type ContainerClientCache = Record<string, ContainerClient>;
11	
12	class AzureCache {
13	    private static instance: AzureCache;
14	    private static tenantId = '';
15	    private static clientId = '';
16	    private static clientSecret = '';
17	    private static storageAccountName = '';
18	    private containerClients: ContainerClientCache = {};
19	
20	    // This is a singleton class, so the constructor is private to prevent external instantiation.
21	    private constructor() { /* empty */ }
22	
23	    private static requireSecret(secretName: string, value: string | undefined): string {
24	        if (!value) {
25	            throw new InternalError(`Missing required Azure secret: ${secretName}.`, {
26	                details: {
27	                    secretName,
28	                },
29	            });
30	        }
31	
32	        return value;
33	    }
34	
35	    public static getInstance(): AzureCache {
36	        if (!AzureCache.instance) {
37	            AzureCache.instance = new AzureCache();
38	            const secrets = getSecrets();
39	
40	            AzureCache.tenantId = AzureCache.requireSecret('AZURE_TENANT_ID', secrets.AZURE_TENANT_ID);
41	            AzureCache.clientId = AzureCache.requireSecret('STORAGE_CLIENT_ID', secrets.STORAGE_CLIENT_ID);
42	            AzureCache.clientSecret = AzureCache.requireSecret('STORAGE_CLIENT_SECRET', secrets.STORAGE_CLIENT_SECRET);
43	            AzureCache.storageAccountName = STORAGE_ACCOUNT_NAME;
44	        }
45	        return AzureCache.instance;
46	    }
47	
48	    private getBlobServiceClient(): BlobServiceClient {
49	        const credentials = new ClientSecretCredential(AzureCache.tenantId, AzureCache.clientId, AzureCache.clientSecret);
50	        return new BlobServiceClient(
51	            `https://${AzureCache.storageAccountName}.blob.core.windows.net`,
52	            credentials,
53	        );
54	    }
55	
56	    public getContainerClient(containerName: string): ContainerClient {
57	        if (!this.containerClients[containerName]) {
58	            try {
59	                const blobServiceClient = this.getBlobServiceClient();
60	                const containerClient = blobServiceClient.getContainerClient(containerName);
61	                this.containerClients[containerName] = containerClient;
62	            } catch (error) {
63	                throw normalizeUnknownError(error, {
64	                    message: `Failed to create Azure container client "${containerName}".`,
65	                    details: {
66	                        containerName,
67	                    },
68	                });
69	            }
70	        }
71	
72	        return this.containerClients[containerName];
73	    }
74	}
75	
76	export default AzureCache.getInstance();
