16	// Helper to find a named component element anywhere in a JSX tree
17	const findElement = (node: unknown, displayName: string): AnyElement | null => {
18	    if (!node || typeof node !== 'object') return null;
19	    const el = node as AnyElement;
20	    if (typeof el.type === 'function') {
21	        const fn = el.type as { displayName?: string; name?: string };
22	        const name = fn.displayName ?? fn.name;
23	        if (name === displayName) return el;
24	    }
25	    const children = (el.props as { children?: unknown }).children;
26	    if (Array.isArray(children)) {
27	        for (const child of children) {
28	            const found = findElement(child, displayName);
29	            if (found) return found;
30	        }
31	    }
32	    return findElement(children, displayName);
33	};
