3	import nodemailer, { type SendMailOptions } from 'nodemailer';
4	import sanitizeHtml from 'sanitize-html';
5	
6	import { sendViaGraphApi } from '@/lib/email/sendViaGraphApi';
7	import { ExternalServiceError, InternalError, normalizeUnknownError } from '@/lib/errors';
8	import { captureUnexpectedError } from '@/lib/observability/sentry';
9	import { getSecrets } from '@/lib/secrets';
10	
11	/**
12	 * Asserts that a secret value is defined, throwing an {@link InternalError}
13	 * with a descriptive message if it is missing.
14	 *
15	 * @param name - The secret name, used in the error message.
16	 * @param value - The secret value to validate.
17	 * @returns The validated non-empty string value.
18	 * @throws {InternalError} If the value is undefined or empty.
19	 */
20	function requireSecret(name: string, value: string | undefined): string {
21	    if (!value) {
22	        throw new InternalError(`Missing required secret for Graph API email: ${name}.`, {
23	            details: { secretName: name },
24	        });
25	    }
26	    return value;
27	}
28	
29	/**
30	 * Converts a nodemailer recipient field to a plain comma-separated string.
31	 *
32	 * Handles `string`, `Address` objects, and arrays of both. Returns `undefined`
33	 * when the input is falsy.
34	 *
35	 * @param value - A nodemailer-style recipient value.
36	 * @returns A comma-separated email string, or `undefined`.
37	 */
38	function recipientToString(
39	    value: SendMailOptions['to'],
40	): string | undefined {
41	    if (!value) return undefined;
42	    if (typeof value === 'string') return value;
43	    if (Array.isArray(value)) {
44	        return value
45	            .map(v => (typeof v === 'string' ? v : v.address))
46	            .join(',');
47	    }
48	    return value.address;
49	}
50	
51	/**
52	 * Sends an email using the configured transport.
53	 *
54	 * In production, uses the Microsoft Graph API with client-credentials OAuth2.
55	 * In development and CI, uses a local SMTP server (e.g. MailPit on port 1025).
56	 * HTML content is sanitized before sending in both cases.
57	 *
58	 * @param mailOptions - Nodemailer mail options payload.
59	 * @throws {ExternalServiceError} If email delivery fails.
60	 */
61	export async function sendEmailCore(mailOptions: SendMailOptions) {
62	    const secrets = getSecrets();
63	
64	    const sanitizedHtml =
65	        typeof mailOptions.html === 'string' ?
66	            sanitizeHtml(mailOptions.html) :
67	            mailOptions.html ?? undefined;
68	
69	    try {
70	        if (process.env.NODE_ENV === 'production' && !process.env.CI && process.env.PLAYWRIGHT_TEST !== 'true') {
71	            await sendViaGraphApi(
72	                {
73	                    to: recipientToString(mailOptions.to),
74	                    cc: recipientToString(mailOptions.cc),
75	                    bcc: recipientToString(mailOptions.bcc),
76	                    subject: mailOptions.subject,
77	                    html: typeof sanitizedHtml === 'string' ? sanitizedHtml : undefined,
78	                },
79	                {
80	                    tenantId: requireSecret('AZURE_TENANT_ID', secrets.AZURE_TENANT_ID),
81	                    clientId: requireSecret('MAIL_GRAPH_CLIENT_ID', secrets.MAIL_GRAPH_CLIENT_ID),
82	                    clientSecret: requireSecret('MAIL_GRAPH_CLIENT_SECRET', secrets.MAIL_GRAPH_CLIENT_SECRET),
83	                    userPrincipalName: secrets.MAIL_FROM_ADDRESS,
84	                },
85	            );
86	        }
87	        else {
88	            const transporter = nodemailer.createTransport({
89	                host: 'localhost',
90	                port: 1025,
91	                secure: false,
92	            });
93	
94	            await transporter.sendMail({
95	                ...mailOptions,
96	                from: `"${secrets.MAIL_FROM_NAME}" <${secrets.MAIL_FROM_ADDRESS}>`,
97	                ...(sanitizedHtml !== undefined ? { html: sanitizedHtml } : {}),
98	            });
99	        }
100	    }
101	    catch (error) {
102	        if (error instanceof ExternalServiceError || error instanceof InternalError) {
103	            throw error;
104	        }
105	
106	        const normalizedError = normalizeUnknownError(error, {
107	            details: {
108	                to: mailOptions.to,
109	                subject: mailOptions.subject,
110	            },
111	        });
112	        captureUnexpectedError(normalizedError, {
113	            layer: 'server-action',
114	            action: 'sendEmailCore',
115	            extra: {
116	                to: mailOptions.to,
117	                subject: mailOptions.subject,
118	            },
119	        });
120	        throw new ExternalServiceError(
121	            `Failed to send email: ${normalizedError.message}`,
122	            {
123	                cause: normalizedError,
124	                details: {
125	                    to: mailOptions.to,
126	                    subject: mailOptions.subject,
127	                },
128	            },
129	        );
130	    }
131	}
