17	 * `SetGameResultInputSchema`.
18	 * @returns A promise that resolves to the updated game day after the result has
19	 * been set.
20	 * @throws {AuthError} When the user is not an admin.
21	 * @throws Will throw a validation error if `rawData` does not conform to
22	 * `SetGameResultInputSchema`.
23	 */
24	export async function setGameResult(rawData: unknown) {
