2	
3	import outcomeService from '@/services/Outcome';
4	import type { SetDrinkersInput, SetDrinkersResult } from '@/types/actions/SetDrinkers';
5	
6	interface SetDrinkersDeps {
7	    outcomeService: Pick<typeof outcomeService, 'getByGameDay' | 'upsert'>;
8	}
9	
10	const defaultDeps: SetDrinkersDeps = {
11	    outcomeService,
12	};
13	
14	/**
15	 * Mirrors the legacy PHP drinkers flow:
16	 * - clear pub value for every listed player
17	 * - set selected players to 1 if they were on team A/B, otherwise 2
18	 */
19	export async function setDrinkersCore(
20	    data: SetDrinkersInput,
21	    deps: SetDrinkersDeps = defaultDeps,
22	): Promise<SetDrinkersResult> {
23	    const existingOutcomes = await deps.outcomeService.getByGameDay(data.gameDayId);
24	    const existingOutcomeByPlayerId = new Map(
25	        existingOutcomes.map((outcome) => [outcome.playerId, outcome]),
26	    );
27	
28	    const uniquePlayers = new Map<number, boolean>();
29	    for (const player of data.players) {
30	        uniquePlayers.set(player.playerId, player.drinker);
31	    }
32	
33	    const allPlayerIds = new Set<number>([
34	        ...existingOutcomeByPlayerId.keys(),
35	        ...uniquePlayers.keys(),
36	    ]);
37	
38	    const players = Array.from(allPlayerIds).map((playerId) => ({
39	        playerId,
40	        drinker: uniquePlayers.get(playerId) ?? false,
41	    }));
42	    const selectedPlayers = players.filter((player) => player.drinker);
43	
44	    await Promise.all(players.map((player) => deps.outcomeService.upsert({
45	        gameDayId: data.gameDayId,
46	        playerId: player.playerId,
47	        pub: player.drinker ?
48	            (existingOutcomeByPlayerId.get(player.playerId)?.team ? 1 : 2) :
49	            null,
50	    })));
51	
52	    return {
53	        gameDayId: data.gameDayId,
54	        updated: players.length,
55	        drinkers: selectedPlayers.length,
56	    };
57	}
