2	
3	import type { TeamName } from 'prisma/zod/schemas';
4	import type { GameDayType } from 'prisma/zod/schemas/models/GameDay.schema';
5	
6	import { NotFoundError } from '@/lib/errors';
7	import gameDayService from '@/services/GameDay';
8	import transactionService from '@/services/Money';
9	import outcomeService from '@/services/Outcome';
10	import type { SetGameResultInput } from '@/types/actions/SetGameResult';
11	import type { PointsValue } from '@/types/Points';
12	
13	interface SetGameResultDeps {
14	    gameDayService: Pick<typeof gameDayService, 'get' | 'update'>;
15	    outcomeService: Pick<typeof outcomeService, 'getByGameDay' | 'upsert'>;
16	    transactionService: Pick<typeof transactionService, 'charge'>;
17	}
18	
19	const defaultDeps: SetGameResultDeps = {
20	    gameDayService,
21	    outcomeService,
22	    transactionService,
23	};
24	
25	/**
26	 * Maps a game winner to the corresponding points awarded to players A and B.
27	 *
28	 * @param winner - The winner of the game: 'A' for player A wins, 'B' for player
29	 * B wins, 'draw' for a tie, or any other value for no result
30	 * @returns An object containing points for both players: - Winner receives 3
31	 * points, loser receives 0 points - Draw results in 1 point for each player -
32	 * No result (default case) returns null for both players
33	 *
34	 * @example
35	 * ```typescript
36	 * mapWinnerToPoints('A');    // Returns { A: 3, B: 0 }
37	 * mapWinnerToPoints('B');    // Returns { A: 0, B: 3 }
38	 * mapWinnerToPoints('draw'); // Returns { A: 1, B: 1 }
39	 * mapWinnerToPoints(null);   // Returns { A: null, B: null }
40	 * ```
41	 */
42	const mapWinnerToPoints = (
43	    winner: SetGameResultInput['winner'],
44	): { A: PointsValue | null; B: PointsValue | null; } => {
45	    switch (winner) {
46	        case 'A':
47	            return { A: 3, B: 0 };
48	        case 'B':
49	            return { A: 0, B: 3 };
50	        case 'draw':
51	            return { A: 1, B: 1 };
52	        default:
53	            return { A: null, B: null };
54	    }
55	};
56	
57	
58	/**
59	 * Updates all outcomes for a given team on a game day, setting their points and
60	 * charging each player.
61	 *
62	 * @param gameDay - The game day whose outcomes should be updated.
63	 * @param team - The team whose outcomes should be updated.
64	 * @param points - The points to assign to each outcome (0, 1, 3, or null).
65	 * @param deps - Services used to load outcomes, persist updates, and charge
66	 * transactions.
67	 * @throws Propagates any errors from outcome or transaction services.
68	 */
69	const updateTeamOutcomes = async (
70	    gameDay: GameDayType,
71	    team: TeamName,
72	    points: PointsValue | null,
73	    deps: SetGameResultDeps,
74	) => {
75	    const outcomes = await deps.outcomeService.getByGameDay(gameDay.id, team);
76	
77	    await Promise.all(outcomes.map((outcome) => (
78	        deps.outcomeService.upsert({
79	            gameDayId: gameDay.id,
80	            playerId: outcome.playerId,
81	            points,
82	        })
83	    )));
84	
85	    await Promise.all(outcomes.map((outcome) => {
86	        return (deps.transactionService.charge(
87	            outcome.playerId,
88	            gameDay.id,
89	            gameDay.cost,
90	        ));
91	    }));
92	};
93	
94	/**
95	 * Sets the result of a game by updating the game day with team information and
96	 * calculating points.
97	 *
98	 * @param data - The game result input containing gameDayId, bibs, and winner
99	 * information
100	 * @param deps - Optional dependencies for services (defaults to defaultDeps)
101	 * @returns A promise that resolves to the updated GameDay object
102	 * @throws {NotFoundError} If the game day with the specified ID is not found.
103	 *
104	 * @remarks
105	 * This function performs the following operations:
106	 * 1. Retrieves the game day by ID
107	 * 2. Updates the game day with bibs information
108	 * 3. Calculates points based on the winner
109	 * 4. Updates points for both teams (A and B) in parallel
110	 */
111	export async function setGameResultCore(
112	    data: SetGameResultInput,
113	    deps: SetGameResultDeps = defaultDeps,
114	): Promise<GameDayType> {
115	    const gameDay = await deps.gameDayService.get(data.gameDayId);
116	    if (!gameDay) {
117	        throw new NotFoundError(`Game day not found (id: ${data.gameDayId}).`);
118	    }
119	
120	    const updatedGameDay = await deps.gameDayService.update({
121	        id: data.gameDayId,
122	        bibs: data.bibs,
123	    });
124	
125	    const pointsByTeam = mapWinnerToPoints(data.winner);
126	
127	    await Promise.all([
128	        updateTeamOutcomes(gameDay, 'A', pointsByTeam.A, deps),
129	        updateTeamOutcomes(gameDay, 'B', pointsByTeam.B, deps),
130	    ]);
131	
132	    return updatedGameDay;
133	}
