33	/**
34	 * Secrets that are only required in production (e.g. Graph API email credentials).
35	 * These are allowed to be missing in development and CI environments.
36	 */
37	const productionOnlySecrets: ReadonlySet<keyof typeof secrets> = new Set([
38	    'MAIL_GRAPH_CLIENT_ID',
39	    'MAIL_GRAPH_CLIENT_SECRET',
40	]);
