42	let cachedSecrets: typeof secrets | null = null;
43	
44	function readFileIfExists(filePath: string): string | undefined {
45	    try {
46	        return fs.readFileSync(filePath, "utf8");
47	    }
48	    catch (error: unknown) {
49	        if (typeof error === "object" &&
50	            error !== null &&
51	            "code" in error &&
52	            (error as { code?: string }).code === "ENOENT") {
53	            return undefined;
54	        }
55	
56	        throw normalizeUnknownError(error, {
57	            message: `Failed to read secret file at ${filePath}.`,
58	            details: {
59	                filePath,
60	            },
61	        });
62	    }
63	}
64	
65	/**
66	 * Load all secrets once and cache in memory.
67	 */
68	export function getSecrets(): typeof secrets {
69	    if (cachedSecrets !== null) {
70	        return cachedSecrets;
71	    }
72	
73	    const result = { ...secrets };
74	    const secretsDir = process.env.SECRETS_DIR;
75	
76	    if (secretsDir) {
77	        for (const key of Object.keys(secrets) as (keyof typeof secrets)[]) {
78	            const value = readFileIfExists(path.join(secretsDir, key));
79	
80	            if (value !== undefined) {
81	                result[key] = value;
82	            }
83	        }
84	    }
85	
86	    const isProduction = process.env.NODE_ENV === 'production';
87	    const missingSecrets = Object.entries(result)
88	        .filter(([key, value]) => {
89	            const isMissing = value === undefined || value === null || value === '';
90	            if (!isMissing) return false;
91	
92	            // Production-only secrets (e.g. Graph API email) are allowed to be
93	            // absent outside production; all other secrets are always required.
94	            if (!isProduction && productionOnlySecrets.has(key as keyof typeof secrets)) {
95	                return false;
96	            }
97	
98	            return true;
99	        })
100	        .map(([key]) => key);
101	
102	    if (missingSecrets.length > 0 && process.env.NODE_ENV !== 'test') {
103	        throw new InternalError('Missing required secrets.', {
104	            details: {
105	                missingSecrets,
106	            },
107	        });
108	    }
109	
110	    cachedSecrets = result;
111	    return cachedSecrets;
112	}
