5	const DEFAULT_TOKEN_BYTES = 32;
6	const DEFAULT_TOKEN_TTL_MS = 1000 * 60 * 60 * 24 * 7;
7	
8	/**
9	 * Creates a verification token along with its hashed representation and expiry
10	 * timestamp.
11	 *
12	 * @param ttlMs - Optional time-to-live for the token in milliseconds. Defaults
13	 * to {@link DEFAULT_TOKEN_TTL_MS}.
14	 * @returns An object containing the plaintext token, its hashed value, and the
15	 * expiration date.
16	 */
17	export function createVerificationToken(ttlMs: number = DEFAULT_TOKEN_TTL_MS) {
18	    const token = crypto.randomBytes(DEFAULT_TOKEN_BYTES).toString('hex');
19	    const tokenHash = hashVerificationToken(token);
20	    const expiresAt = new Date(Date.now() + ttlMs);
21	
22	    return { token, tokenHash, expiresAt };
23	}
