25	/**
26	 * Generates a SHA-256 hash of the provided verification token and returns it as
27	 * a hexadecimal string.
28	 *
29	 * @param token - The verification token to hash.
30	 * @returns The hexadecimal digest of the token's SHA-256 hash.
31	 */
32	export function hashVerificationToken(token: string) {
33	    return crypto.createHash('sha256').update(token).digest('hex');
34	}
