3	 *
4	 * @param readableStream - The readable stream to convert.
5	 * @returns A promise that resolves to a Buffer containing the data from the stream.
6	 *
7	 * @example
8	 * ```typescript
9	 * import { streamToBuffer } from './utils';
10	 * import { createReadStream } from 'fs';
11	 *
12	 * const readableStream = createReadStream('path/to/file');
