17	export async function streamToBuffer(readableStream: NodeJS.ReadableStream): Promise<Buffer> {
18	    return new Promise((resolve, reject) => {
19	        const chunks: Buffer[] = [];
20	        readableStream.on('data', (data: Buffer | Uint8Array) => {
21	            chunks.push(Buffer.isBuffer(data) ? data : Buffer.from(data));
22	        });
23	        readableStream.on('end', () => {
24	            resolve(Buffer.concat(chunks));
25	        });
26	        readableStream.on('error', reject);
27	    });
28	}
