80	/**
81	 * Determines the result state for a specific team based on the game winner.
82	 *
83	 * @param team - The name of the team to check the result for
84	 * @param winner - The winner of the game (can be a team name, 'draw', or null)
85	 * @returns The result state for the specified team:
86	 *   - 'unset' if the winner is null (game not yet decided)
87	 *   - 'draw' if the game ended in a draw
88	 *   - 'win' if the specified team won
89	 *   - 'loss' if the specified team lost
90	 */
91	export const getTeamResultState = (
92	    team: TeamName,
93	    winner: GameWinner,
94	): TeamResultState => {
95	    if (winner === null) return 'unset';
96	    if (winner === 'draw') return 'draw';
97	    if (winner === team) return 'win';
98	    return 'loss';
